5	const basePremium = (type: string): number => {
6	  if (type === "amulet") return 60;
7	  return 100;
8	};
9	
10	const roundUp = (value: number): number => {
11	  const epsilon = 1e-9;
12	  return Math.ceil(value - epsilon);
13	};
14	
15	export const run = (input: Input): unknown => {
16	  const results = input.steps.map((step) => {
17	    const base = basePremium(step.items[0].type);
18	    const withFirst = base * 1.1;
19	    const premium = roundUp(withFirst) + 5;
20	    return { premium };
21	  });
22	  return { results };
23	};
