const FIRST_INSURANCE_SURCHARGE = 1.1;
const PROCESSING_FEE = 5;

export const run = (input: Input): unknown => {
  const results = input.steps.map((step) => {
    const base = basePremium(step.items[0].type);
    const withFirstInsurance = base * FIRST_INSURANCE_SURCHARGE;
    const premium = roundUp(withFirstInsurance) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};
